// Check user preferences before sending (if preferences service is configured).
// The recipient may be an email address or a userId; we check both as the
// userId in metadata (set by event handlers) and the recipient itself.
const recipientUserId = (input.metadata?.['userId'] as string | undefined) ?? input.recipient;
if (this.preferencesService) {
  const shouldSend = this.preferencesService.shouldSendNotification(
    recipientUserId,
    channel,
    input.type,
  );
  if (!shouldSend) {
    this.logger.info(
      `Notification suppressed by user preferences: ${input.type} for ${recipientUserId} via ${channel}`,
    );
    // Return a record with 'suppressed' info but do not dispatch.
    const suppressedRecord: NotificationRecord = {
      id: generateNotificationId(),
      type: input.type,
      channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      status: 'failed',
      priority,
      metadata: { ...input.metadata, suppressedByPreferences: true },
      createdAt: new Date(),
      failureReason: 'Suppressed by user notification preferences',
    };
    this.notifications.push(suppressedRecord);
    return suppressedRecord;
  }
}

