import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { UserCreatedEvent, OrderCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new PreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('createPreferences', () => {
    it('should create default preferences for a user', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categoryPreferences).toHaveLength(4);
      expect(prefs.createdAt).toBeInstanceOf(Date);
      expect(prefs.updatedAt).toBeInstanceOf(Date);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'daily',
          categoryPreferences: [
            { category: 'order_confirmation', enabled: true },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: false },
            { category: 'account_updated', enabled: false },
          ],
        },
      });

      expect(prefs.email.frequency).toBe('daily');
      expect(prefs.email.categoryPreferences).toHaveLength(4);
      const welcomePref = prefs.email.categoryPreferences.find(
        (cp) => cp.category === 'welcome',
      );
      expect(welcomePref?.enabled).toBe(false);
    });

    it('should apply defaults for omitted email fields', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'weekly' },
      });

      expect(prefs.email.enabled).toBe(true); // default
      expect(prefs.email.frequency).toBe('weekly'); // overridden
      expect(prefs.email.categoryPreferences).toHaveLength(4); // default
    });

    it('should throw if preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => {
        service.createPreferences({ userId: 'user-1' });
      }).toThrow('Preferences already exist for user: user-1');
    });

    it('should generate sequential preference IDs', () => {
      const prefs1 = service.createPreferences({ userId: 'user-1' });
      const prefs2 = service.createPreferences({ userId: 'user-2' });

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for an existing user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs?.userId).toBe('user-1');
    });

    it('should return undefined for a user without preferences', () => {
      const prefs = service.getPreferences('user-999');
      expect(prefs).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled flag', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily' },
      });

      expect(updated.email.frequency).toBe('daily');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update category preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: true },
            { category: 'order_status_update', enabled: false },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: false },
          ],
        },
      });

      const statusUpdatePref = updated.email.categoryPreferences.find(
        (cp) => cp.category === 'order_status_update',
      );
      expect(statusUpdatePref?.enabled).toBe(false);
    });

    it('should throw if preferences do not exist', () => {
      expect(() => {
        service.updatePreferences('user-999', {
          email: { enabled: false },
        });
      }).toThrow('No preferences found for user: user-999');
    });

    it('should update the updatedAt timestamp', () => {
      const created = service.createPreferences({ userId: 'user-1' });
      const createdTime = created.updatedAt.getTime();

      // Small delay to ensure distinct timestamp
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'weekly' },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(createdTime);
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const result = service.deletePreferences('user-1');
      expect(result).toBe(true);

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeUndefined();
    });

    it('should return false if no preferences exist', () => {
      const result = service.deletePreferences('user-999');
      expect(result).toBe(false);
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should return existing preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { frequency: 'daily' },
      });

      const prefs = service.getOrCreatePreferences('user-1');
      expect(prefs.email.frequency).toBe('daily');
    });

    it('should create default preferences if none exist', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true if no preferences are stored (opt-out model)', () => {
      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      service.createPreferences({ userId: 'user-1' });

      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(true);
    });

    it('should return false when email master switch is disabled', () => {
      service.createPreferences({ userId: 'user-1' });
      service.updatePreferences('user-1', { email: { enabled: false } });

      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(false);
    });

    it('should return false when specific category is disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: false },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: true },
          ],
        },
      });

      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(false);
    });

    it('should return true for categories not explicitly listed', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [], // No categories listed
        },
      });

      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(true);
    });

    it('should return false when master switch is off even if category is enabled', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          enabled: false,
          categoryPreferences: [
            { category: 'order_confirmation', enabled: true },
          ],
        },
      });

      const result = service.shouldSendNotification(
        'user-1',
        'email',
        'order_confirmation',
      );
      expect(result).toBe(false);
    });

    it('should return true for non-email channels (unsupported default to send)', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      // Even though email is disabled, SMS should default to sending.
      const result = service.shouldSendNotification(
        'user-1',
        'sms',
        'order_confirmation',
      );
      expect(result).toBe(true);
    });

    it('should independently handle preferences for different users', () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });
      service.createPreferences({
        userId: 'user-2',
        email: { enabled: true },
      });

      expect(
        service.shouldSendNotification('user-1', 'email', 'welcome'),
      ).toBe(false);
      expect(
        service.shouldSendNotification('user-2', 'email', 'welcome'),
      ).toBe(true);
    });

    it('should correctly check different categories for the same user', () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: true },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: false },
            { category: 'account_updated', enabled: false },
          ],
        },
      });

      expect(
        service.shouldSendNotification('user-1', 'email', 'order_confirmation'),
      ).toBe(true);
      expect(
        service.shouldSendNotification('user-1', 'email', 'welcome'),
      ).toBe(false);
      expect(
        service.shouldSendNotification('user-1', 'email', 'account_updated'),
      ).toBe(false);
      expect(
        service.shouldSendNotification('user-1', 'email', 'order_status_update'),
      ).toBe(true);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter({ stubMode: true });
      notificationService.registerAdapter(emailAdapter);
      notificationService.setPreferencesService(service);
      resetNotificationIdCounter();
    });

    it('should send notifications when user has no preferences (opt-out)', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');
    });

    it('should suppress notifications when email is disabled', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toContain('Suppressed by user notification preferences');
      expect(notifications[0]?.metadata?.['suppressedByPreferences']).toBe(true);
    });

    it('should suppress notifications for disabled category', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: false },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: true },
          ],
        },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toContain('Suppressed');
    });

    it('should send notifications for enabled categories even when some are disabled', async () => {
      service.createPreferences({
        userId: 'user-1',
        email: {
          categoryPreferences: [
            { category: 'order_confirmation', enabled: false },
            { category: 'order_status_update', enabled: true },
            { category: 'welcome', enabled: true },
            { category: 'account_updated', enabled: false },
          ],
        },
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.type).toBe('welcome');
    });

    it('should work without preferences service (backwards compatible)', async () => {
      // Create a new notification service without preferences
      const plainNotifService = new NotificationService(eventBus);
      plainNotifService.registerAdapter(emailAdapter);

      // The event handlers from the first notificationService will also fire,
      // so we create a fresh eventBus for clean testing
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);
      freshNotifService.registerAdapter(new EmailAdapter({ stubMode: true }));
      // Note: no setPreferencesService call

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await freshEventBus.emit(event);

      const notifications = freshNotifService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');
    });
  });
});

