+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a fully implemented email adapter with:
+ * - Template rendering: Generates HTML and plain-text email bodies
+ *   based on notification type (order confirmation, welcome, etc.)
+ * - Recipient validation: Validates email address format before sending.
+ * - Configurable delivery: Stub mode for development/testing, production
+ *   mode for real SMTP/API integration.
+ *
+ * Implements the NotificationAdapter interface. Registered with the
+ * NotificationService to handle all notifications on the 'email' channel.
+ *
+ * Configuration is injected via constructor to support different
+ * environments (dev, staging, production).
+ */
+import { Logger } from '../utils/logger.js';
+/**
+ * Default configuration for development/testing.
+ */
+export const defaultEmailConfig = {
+    host: 'localhost',
+    port: 587,
+    fromAddress: 'noreply@taskflow.dev',
+    stubMode: true,
+    companyName: 'TaskFlow Pro',
+    maxRetries: 3,
+};
+// ---------------------------------------------------------------------------
+// Email Validation
+// ---------------------------------------------------------------------------
+/**
+ * Validates an email address format.
+ *
+ * Uses a reasonable regex that covers the vast majority of valid email
+ * addresses without being overly permissive. Checks:
+ * - Has exactly one @ symbol
+ * - Local part is non-empty and uses allowed characters
+ * - Domain has at least one dot and valid characters
+ * - Domain TLD is at least 2 characters
+ *
+ * @param email - The email address to validate.
+ * @returns true if the email format is valid.
+ */
+export function isValidEmail(email) {
+    if (!email || typeof email !== 'string') {
+        return false;
+    }
+    const trimmed = email.trim();
+    if (trimmed.length === 0 || trimmed.length > 254) {
+        return false;
+    }
+    // Standard email validation regex
+    const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;
+    return emailRegex.test(trimmed);
+}
+/**
+ * Resolves a recipient identifier to a normalised string.
+ *
+ * Trims whitespace and normalises to lowercase. If the recipient looks
+ * like a valid email address, it is returned as-is. If it doesn't look
+ * like an email (e.g., a user ID like "user-1"), it is still returned
+ * but marked as unvalidated — the caller can decide how to handle it.
+ *
+ * Returns null only if the input is empty or not a string.
+ *
+ * @param recipient - The recipient string from the notification payload.
+ * @returns An object with the normalised recipient and whether it's a valid email, or null if empty.
+ */
+export function resolveRecipient(recipient) {
+    if (!recipient || typeof recipient !== 'string') {
+        return null;
+    }
+    const normalised = recipient.trim().toLowerCase();
+    if (normalised.length === 0) {
+        return null;
+    }
+    return {
+        address: normalised,
+        isValidEmail: isValidEmail(normalised),
+    };
+}
+// ---------------------------------------------------------------------------
+// Email Template Engine
+// ---------------------------------------------------------------------------
+/**
+ * Renders an email template for the given notification payload.
+ *
+ * Each notification type has a dedicated template that generates both
+ * HTML and plain-text versions of the email. The templates include
+ * proper formatting, branding, and contextual content based on the
+ * notification type and metadata.
+ *
+ * @param payload - The notification payload to render.
+ * @param companyName - The company name for branding.
+ * @returns A rendered email with HTML, text, and subject.
+ */
+export function renderEmailTemplate(payload, companyName) {
+    switch (payload.type) {
+        case 'order_confirmation':
+            return renderOrderConfirmation(payload, companyName);
+        case 'order_status_update':
+            return renderOrderStatusUpdate(payload, companyName);
+        case 'welcome':
+            return renderWelcome(payload, companyName);
+        case 'account_updated':
+            return renderAccountUpdated(payload, companyName);
+        default:
+            return renderGeneric(payload, companyName);
+    }
+}
+/**
+ * Wraps HTML content in a standard email layout with header and footer.
+ */
+function wrapHtmlLayout(title, bodyContent, companyName) {
+    return `<!DOCTYPE html>
+<html>
+<head>
+  <meta charset="utf-8">
+  <title>${escapeHtml(title)}</title>
+</head>
+<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto; padding: 20px;">
+  <div style="border-bottom: 2px solid #007bff; padding-bottom: 10px; margin-bottom: 20px;">
+    <h2 style="color: #007bff; margin: 0;">${escapeHtml(companyName)}</h2>
+  </div>
+  ${bodyContent}
+  <div style="border-top: 1px solid #ddd; padding-top: 15px; margin-top: 30px; font-size: 12px; color: #888;">
+    <p>This is an automated message from ${escapeHtml(companyName)}. Please do not reply directly to this email.</p>
+  </div>
+</body>
+</html>`;
+}
+/**
+ * Escapes HTML special characters to prevent XSS in email templates.
+ */
+function escapeHtml(text) {
+    return text
+        .replace(/&/g, '&amp;')
+        .replace(/</g, '&lt;')
+        .replace(/>/g, '&gt;')
+        .replace(/"/g, '&quot;')
+        .replace(/'/g, '&#039;');
+}
+function renderOrderConfirmation(payload, companyName) {
+    const bodyHtml = `
+  <h3 style="color: #28a745;">Order Confirmed!</h3>
+  <p>Thank you for your order.</p>
+  <div style="background: #f8f9fa; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <p style="margin: 0;">${escapeHtml(payload.body)}</p>
+  </div>
+  <p>We'll send you updates as your order progresses.</p>`;
+    return {
+        subject: payload.subject,
+        html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+        text: `${companyName}\n\nOrder Confirmed!\n\nThank you for your order.\n\n${payload.body}\n\nWe'll send you updates as your order progresses.\n\nThis is an automated message from ${companyName}.`,
+    };
+}
+function renderOrderStatusUpdate(payload, companyName) {
+    const isHighPriority = payload.priority === 'high' || payload.priority === 'urgent';
+    const statusColor = isHighPriority ? '#dc3545' : '#17a2b8';
+    const statusIcon = isHighPriority ? '⚠️' : 'ℹ️';
+    const bodyHtml = `
+  <h3 style="color: ${statusColor};">${statusIcon} Order Status Update</h3>
+  <div style="background: #f8f9fa; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <p style="margin: 0;">${escapeHtml(payload.body)}</p>
+  </div>
+  <p>If you have any questions, please contact our support team.</p>`;
+    return {
+        subject: payload.subject,
+        html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+        text: `${companyName}\n\n${statusIcon} Order Status Update\n\n${payload.body}\n\nIf you have any questions, please contact our support team.\n\nThis is an automated message from ${companyName}.`,
+    };
+}
+function renderWelcome(payload, companyName) {
+    const bodyHtml = `
+  <h3 style="color: #007bff;">Welcome! 🎉</h3>
+  <p>${escapeHtml(payload.body)}</p>
+  <div style="background: #e7f3ff; padding: 15px; border-radius: 5px; margin: 15px 0;">
+    <h4 style="margin-top: 0;">Getting Started:</h4>
+    <ul>
+      <li>Browse our product catalog</li>
+      <li>Set up your profile preferences</li>
+      <li>Place your first order</li>
+    </ul>
+  </div>
+  <p>We're excited to have you on board!</p>`;
+    return {
+        subject: payload.subject,
+        html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+        text: `${companyName}\n\nWelcome! 🎉\n\n${payload.body}\n\nGetting Started:\n- Browse our product catalog\n- Set up your profile preferences\n- Place your first order\n\nWe're excited to have you on board!\n\nThis is an automated message from ${companyName}.`,
+    };
+}
+function renderAccountUpdated(payload, companyName) {
+    const bodyHtml = `
+  <h3 style="color: #ffc107;">Account Updated</h3>
+  <p>${escapeHtml(payload.body)}</p>
+  <p style="color: #666;">If you did not make these changes, please contact our support team immediately.</p>`;
+    return {
+        subject: payload.subject,
+        html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+        text: `${companyName}\n\nAccount Updated\n\n${payload.body}\n\nIf you did not make these changes, please contact our support team immediately.\n\nThis is an automated message from ${companyName}.`,
+    };
+}
+function renderGeneric(payload, companyName) {
+    const bodyHtml = `
+  <h3>${escapeHtml(payload.subject)}</h3>
+  <p>${escapeHtml(payload.body)}</p>`;
+    return {
+        subject: payload.subject,
+        html: wrapHtmlLayout(payload.subject, bodyHtml, companyName),
+        text: `${companyName}\n\n${payload.subject}\n\n${payload.body}\n\nThis is an automated message from ${companyName}.`,
+    };
+}
+// ---------------------------------------------------------------------------
+// EmailAdapter Implementation
+// ---------------------------------------------------------------------------
+/**
+ * Email notification adapter.
+ *
+ * Sends notifications via email with full template rendering and
+ * recipient validation. In stub mode (default), logs the email details
+ * and records them in memory instead of actually delivering.
+ *
+ * Pipeline:
+ * 1. Validate recipient email address format.
+ * 2. Render notification into HTML + plain-text email templates.
+ * 3. Compose complete EmailMessage (from, to, subject, body).
+ * 4. Deliver via stub (log + record) or production (SMTP/API).
+ * 5. Return success/failure result (never throws).
+ */
+export class EmailAdapter {
+    channel = 'email';
+    logger = new Logger('EmailAdapter');
+    config;
+    sentEmails = [];
+    constructor(config) {
+        this.config = { ...defaultEmailConfig, ...config };
+    }
+    /**
+     * Send a notification via email.
+     *
+     * Full pipeline:
+     * 1. Validates the recipient email address.
+     * 2. Renders notification type-specific HTML/text templates.
+     * 3. Composes the complete email message.
+     * 4. Delivers via stub (records in memory) or production mode.
+     *
+     * @param payload - The notification payload to deliver via email.
+     * @returns Result indicating success or failure. Never throws.
+     */
+    async send(payload) {
+        const result = {
+            success: false,
+            notificationId: '',
+            channel: 'email',
+        };
+        try {
+            // Step 1: Validate and resolve recipient
+            const resolved = resolveRecipient(payload.recipient);
+            if (!resolved) {
+                result.failureReason = `Invalid recipient: empty or missing recipient address`;
+                this.logger.warn(result.failureReason);
+                return result;
+            }
+            if (!resolved.isValidEmail) {
+                // Recipient is not a valid email format (could be a user ID or alias).
+                // In stub mode we proceed with a warning; in production we reject.
+                if (!this.config.stubMode) {
+                    result.failureReason = `Invalid recipient email address: "${payload.recipient}"`;
+                    this.logger.warn(result.failureReason);
+                    return result;
+                }
+                this.logger.warn(`Recipient "${payload.recipient}" is not a valid email address; proceeding in stub mode`);
+            }
+            const resolvedRecipient = resolved.address;
+            // Step 2: Render email template
+            const rendered = renderEmailTemplate(payload, this.config.companyName);
+            // Step 3: Compose complete email message
+            const email = {
+                from: this.config.fromAddress,
+                to: resolvedRecipient,
+                subject: rendered.subject,
+                html: rendered.html,
+                text: rendered.text,
+                composedAt: new Date(),
+                notificationType: payload.type,
+                metadata: payload.metadata,
+            };
+            // Step 4: Deliver
+            if (this.config.stubMode) {
+                // Stub mode: log and record instead of sending
+                this.logger.info(`[STUB] Email to ${email.to}: "${email.subject}"`);
+                this.sentEmails.push(email);
+            }
+            else {
+                // Production mode: attempt real delivery with retries
+                await this.deliverWithRetry(email);
+            }
+            result.success = true;
+            this.logger.info(`Email sent to ${email.to}`);
+        }
+        catch (error) {
+            const message = error instanceof Error ? error.message : 'Unknown email delivery error';
+            result.success = false;
+            result.failureReason = message;
+            this.logger.error(`Email delivery failed for ${payload.recipient}: ${message}`);
+        }
+        return result;
+    }
+    /**
+     * Get all emails sent in stub mode. Useful for testing.
+     *
+     * Returns defensive copies of the recorded email messages,
+     * including the rendered HTML and plain-text content.
+     */
+    getSentEmails() {
+        return [...this.sentEmails];
+    }
+    /**
+     * Clear sent email records. Useful for testing.
+     */
+    clearSentEmails() {
+        this.sentEmails = [];
+    }
+    /**
+     * Get the current adapter configuration.
+     */
+    getConfig() {
+        return { ...this.config };
+    }
+    /**
+     * Render a template for a given payload without sending.
+     * Useful for previewing emails or testing templates in isolation.
+     *
+     * @param payload - The notification payload to render.
+     * @returns The rendered email content (HTML, text, subject).
+     */
+    renderTemplate(payload) {
+        return renderEmailTemplate(payload, this.config.companyName);
+    }
+    /**
+     * Validate a recipient email address without sending.
+     *
+     * @param recipient - The email address to validate.
+     * @returns true if the email address is valid.
+     */
+    validateRecipient(recipient) {
+        const resolved = resolveRecipient(recipient);
+        return resolved !== null && resolved.isValidEmail;
+    }
+    // -------------------------------------------------------------------------
+    // Private Delivery Methods
+    // -------------------------------------------------------------------------
+    /**
