+    private orderRepository;
+    private userRepository;
+    private eventBus;
+    private logger;
+    constructor(orderRepository: OrderRepository, userRepository: UserRepository, eventBus: EventBus);
+    /**
+     * Create a new order for a user.
+     */
+    createOrder(input: CreateOrderInput): Promise<Order>;
+    /**
+     * Get an order by ID.
+     */
+    getOrder(id: string): Order | undefined;
+    /**
+     * Update order status.
+     */
+    updateOrderStatus(id: string, newStatus: OrderStatus): Promise<Order>;
+    /**
+     * List orders for a user.
+     */
+    listUserOrders(userId: string): Order[];
+    /**
+     * List orders by status.
+     */
+    listOrdersByStatus(status: OrderStatus): Order[];
+    /**
+     * Validate that a status transition is allowed.
+     */
