+} from '../../src/services/notification.service.js';
+import { EmailAdapter } from '../../src/adapters/email.adapter.js';
+import type { UserCreatedEvent, OrderCreatedEvent } from '../../src/events/event-types.js';
+
+describe('PreferencesService', () => {
+  let db: Database;
+  let repo: PreferencesRepository;
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    db = new Database();
+    repo = new PreferencesRepository(db);
+    service = new PreferencesService(repo);
+    resetPreferencesIdCounter();
+  });
+
+  describe('createPreferences', () => {
+    it('should create default preferences for a user', () => {
+      const prefs = service.createPreferences({ userId: 'user-1' });
+
+      expect(prefs.id).toBe('pref-0001');
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.email.enabled).toBe(true);
+      expect(prefs.email.frequency).toBe('immediate');
+      expect(prefs.email.categoryPreferences).toHaveLength(4);
+      expect(prefs.createdAt).toBeInstanceOf(Date);
+      expect(prefs.updatedAt).toBeInstanceOf(Date);
+    });
+
+    it('should create preferences with custom email settings', () => {
+      const prefs = service.createPreferences({
+        userId: 'user-1',
+        email: {
+          enabled: true,
+          frequency: 'daily',
+          categoryPreferences: [
+            { category: 'order_confirmation', enabled: true },
+            { category: 'order_status_update', enabled: true },
+            { category: 'welcome', enabled: false },
+            { category: 'account_updated', enabled: false },
+          ],
+        },
+      });
+
+      expect(prefs.email.frequency).toBe('daily');
+      expect(prefs.email.categoryPreferences).toHaveLength(4);
+      const welcomePref = prefs.email.categoryPreferences.find(
+        (cp) => cp.category === 'welcome',
+      );
+      expect(welcomePref?.enabled).toBe(false);
+    });
+
+    it('should apply defaults for omitted email fields', () => {
+      const prefs = service.createPreferences({
+        userId: 'user-1',
+        email: { frequency: 'weekly' },
+      });
+
+      expect(prefs.email.enabled).toBe(true); // default
+      expect(prefs.email.frequency).toBe('weekly'); // overridden
+      expect(prefs.email.categoryPreferences).toHaveLength(4); // default
+    });
+
+    it('should throw if preferences already exist for user', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      expect(() => {
+        service.createPreferences({ userId: 'user-1' });
+      }).toThrow('Preferences already exist for user: user-1');
+    });
+
+    it('should generate sequential preference IDs', () => {
+      const prefs1 = service.createPreferences({ userId: 'user-1' });
+      const prefs2 = service.createPreferences({ userId: 'user-2' });
+
+      expect(prefs1.id).toBe('pref-0001');
+      expect(prefs2.id).toBe('pref-0002');
+    });
+  });
+
+  describe('getPreferences', () => {
+    it('should return preferences for an existing user', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      const prefs = service.getPreferences('user-1');
+      expect(prefs).toBeDefined();
+      expect(prefs?.userId).toBe('user-1');
+    });
+
+    it('should return undefined for a user without preferences', () => {
+      const prefs = service.getPreferences('user-999');
+      expect(prefs).toBeUndefined();
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should update email enabled flag', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      const updated = service.updatePreferences('user-1', {
+        email: { enabled: false },
+      });
+
+      expect(updated.email.enabled).toBe(false);
+      expect(updated.email.frequency).toBe('immediate'); // unchanged
+    });
+
+    it('should update email frequency', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      const updated = service.updatePreferences('user-1', {
+        email: { frequency: 'daily' },
+      });
+
+      expect(updated.email.frequency).toBe('daily');
+      expect(updated.email.enabled).toBe(true); // unchanged
+    });
+
+    it('should update category preferences', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      const updated = service.updatePreferences('user-1', {
+        email: {
+          categoryPreferences: [
+            { category: 'order_confirmation', enabled: true },
+            { category: 'order_status_update', enabled: false },
+            { category: 'welcome', enabled: true },
+            { category: 'account_updated', enabled: false },
